import { Checkbox as CheckboxPrimitive } from '@base-ui/react/checkbox';
import { clsx } from 'clsx';
import { forwardRef, type ComponentProps, type ComponentRef } from 'react';
import { CheckIcon, IndeterminateIcon } from '@/lib/moduix/icons/ui';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Checkbox.module.css';

type CheckboxSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl';
type CheckboxProps = CheckboxPrimitive.Root.Props & { size?: CheckboxSize };

const Checkbox = forwardRef<ComponentRef<typeof CheckboxPrimitive.Root>, CheckboxProps>(
  function Checkbox({ className, size = 'md', children, ...props }, ref) {
    return (
      <CheckboxPrimitive.Root
        ref={ref}
        data-slot="checkbox-root"
        data-size={size}
        className={mergeClassName(className, styles.root)}
        {...props}
      >
        {children ?? <CheckboxIndicator />}
      </CheckboxPrimitive.Root>
    );
  },
);

function CheckboxIndicator({ className, children, ...props }: CheckboxPrimitive.Indicator.Props) {
  return (
    <CheckboxPrimitive.Indicator
      data-slot="checkbox-indicator"
      className={mergeClassName(className, styles.indicator)}
      {...props}
    >
      {children ?? <CheckboxIndicatorIcon />}
    </CheckboxPrimitive.Indicator>
  );
}

function CheckboxIndicatorIcon({ className, children, ...props }: ComponentProps<'span'>) {
  return (
    <span
      aria-hidden="true"
      data-slot="checkbox-indicator-icon"
      className={clsx(styles.icon, className)}
      {...props}
    >
      {children ?? (
        <>
          <span data-slot="checkbox-indicator-checked-icon" className={styles.iconChecked}>
            <CheckIcon />
          </span>
          <span
            data-slot="checkbox-indicator-indeterminate-icon"
            className={styles.iconIndeterminate}
          >
            <IndeterminateIcon />
          </span>
        </>
      )}
    </span>
  );
}

function CheckboxField({ className, ...props }: ComponentProps<'label'>) {
  return <label data-slot="checkbox-field" className={clsx(styles.field, className)} {...props} />;
}

function CheckboxLabel({ className, ...props }: ComponentProps<'span'>) {
  return <span data-slot="checkbox-label" className={clsx(styles.label, className)} {...props} />;
}

export { Checkbox, CheckboxIndicator, CheckboxIndicatorIcon, CheckboxField, CheckboxLabel };

@layer ui.components {
  .field {
    display: inline-flex;
    align-items: center;
    gap: var(--checkbox-gap, var(--spacing-2));
    vertical-align: middle;
    cursor: pointer;

    &:has(.root[data-disabled]),
    &:has(.root[data-readonly]) {
      cursor: default;
    }
  }

  .root {
    box-sizing: border-box;
    display: inline-flex;
    flex: none;
    align-items: center;
    justify-content: center;
    width: var(--_checkbox-size, 1.25rem);
    height: var(--_checkbox-size, 1.25rem);
    margin: 0;
    border: var(--checkbox-border-width, var(--border-width-sm)) solid
      var(--checkbox-border-color, var(--color-border));
    border-radius: var(--checkbox-radius, var(--radius-xs));
    padding: 0;
    background-color: var(--checkbox-bg, var(--color-background));
    color: var(--checkbox-color, var(--color-primary-foreground));
    outline: 0;
    line-height: 0;
    user-select: none;
    cursor: pointer;
    transition:
      background-color var(--checkbox-transition, var(--transition-default)),
      border-color var(--checkbox-transition, var(--transition-default)),
      color var(--checkbox-transition, var(--transition-default)),
      opacity var(--checkbox-transition, var(--transition-default));

    &[data-checked],
    &[data-indeterminate] {
      border-color: var(--checkbox-border-color-checked, var(--color-primary));
      background-color: var(--checkbox-bg-checked, var(--color-primary));
    }

    &:focus-visible {
      outline: var(--checkbox-focus-ring-width, var(--border-width-sm)) solid
        var(--checkbox-focus-ring-color, var(--color-ring));
      outline-offset: var(--checkbox-focus-ring-offset, var(--border-width-sm));
    }

    @media (hover: hover) {
      &[data-unchecked]:not([data-readonly]):hover {
        background-color: var(--checkbox-bg-hover, var(--color-accent));
      }
    }

    &[data-readonly] {
      cursor: default;
    }

    &[data-disabled] {
      opacity: var(--checkbox-disabled-opacity, var(--opacity-disabled));
      pointer-events: none;
    }
    &[data-size='xs'] {
      --_checkbox-size: var(--checkbox-size-xs, 0.875rem);
      --_checkbox-icon-size: var(--checkbox-icon-size-xs, 0.5rem);
    }

    &[data-size='sm'] {
      --_checkbox-size: var(--checkbox-size-sm, 1rem);
      --_checkbox-icon-size: var(--checkbox-icon-size-sm, 0.625rem);
    }

    &[data-size='md'] {
      --_checkbox-size: var(--checkbox-size-md, 1.25rem);
      --_checkbox-icon-size: var(--checkbox-icon-size-md, 0.75rem);
    }

    &[data-size='lg'] {
      --_checkbox-size: var(--checkbox-size-lg, 1.5rem);
      --_checkbox-icon-size: var(--checkbox-icon-size-lg, 0.875rem);
    }

    &[data-size='xl'] {
      --_checkbox-size: var(--checkbox-size-xl, 1.75rem);
      --_checkbox-icon-size: var(--checkbox-icon-size-xl, 1rem);
    }
  }

  .indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 100%;
    height: 100%;

    &[data-indeterminate] {
      .iconChecked {
        display: none;
      }
    }

    &[data-checked] {
      .iconIndeterminate {
        display: none;
      }
    }

    &[data-unchecked] {
      .iconChecked,
      .iconIndeterminate {
        display: none;
      }
    }
  }

  .icon {
    display: flex;
    align-items: center;
    justify-content: center;
    width: var(--_checkbox-icon-size, 0.75rem);
    height: var(--_checkbox-icon-size, 0.75rem);
    color: inherit;
    line-height: 0;
  }

  .iconChecked,
  .iconIndeterminate {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 100%;
    height: 100%;

    & > svg {
      width: 100%;
      height: 100%;
    }
  }

  .label {
    color: var(--checkbox-label-color, var(--color-foreground));
    font-size: var(--checkbox-label-font-size, var(--text-sm));
    font-weight: var(--checkbox-label-font-weight, var(--weight-medium));
    line-height: var(--checkbox-label-line-height, var(--line-height-text-sm));
  }
}

export {
  Checkbox,
  CheckboxIndicator,
  CheckboxIndicatorIcon,
  CheckboxField,
  CheckboxLabel,
} from './Checkbox';
